00177 void run_all_tests(void)
00178 {
00179     uint32_t val = 0;
00180 
00181     printf("=== Lancement des tests unitaires ===\n");
00182 
00183     // ---------------------------------------------------------
00184     // TEST 1 : Cas d'erreurs de set_tag
00185     // ---------------------------------------------------------
00186     printf("Test 1: Erreurs de set_tag... ");
00187     init_tag_manager(); // On part d'un état propre
00188 
00189     // Tailles invalides (ex: 0 retourne CAN_TG_ERROR_SIZE_VALUE_INVALIDE)
00190     printf("\tTailles invalides\n");
00191     TEST_EQ_INT("0",set_tag("inv1", 0), CAN_TG_ERROR_SIZE_VALUE_INVALIDE);
00192     TEST_EQ_INT("2",set_tag("inv2", 2), CAN_TG_SUCCESS);
00193     TEST_EQ_INT("5",set_tag("inv5", 5), CAN_TG_SUCCESS);
00194 
00195     // Tag en double (retour attendu: CAN_TG_ERROR_NAME_ALREADY_USE)
00196     printf("\tTag en double\n");
00197     TEST_EQ_INT("première insertion",set_tag("TAG_A", 4), SUCCES_TO_SET); // Succès
00198     TEST_EQ_INT("duplica détection",set_tag("TAG_A", 3), CAN_TG_ERROR_NAME_ALREADY_USE); // Erreur : existe déjà
00199     printf("OK\n");
00200 
00201     // ---------------------------------------------------------
00202     // TEST 2 : Dépassement de l'espace mémoire (8 octets max)
00203     // ---------------------------------------------------------
00204     printf("Test 2: Remplissage memoire (8 bytes max)... ");
00205     init_tag_manager();
00206 
00207     // On ajoute 4 tags de 16 bits (4 * 2 = 8 octets complets)
00208     printf("\tpreparation du GT\n");
00209     TEST_EQ_INT("ajout de valeurs 16 bit (1/4)",set_tag("T1", 16), SUCCES_TO_SET);
00210     TEST_EQ_INT("ajout de valeurs 16 bit (2/4)",set_tag("T2", 16), SUCCES_TO_SET);
00211     TEST_EQ_INT("ajout de valeurs 16 bit (3/4)",set_tag("T3", 16), SUCCES_TO_SET);
00212     TEST_EQ_INT("ajout de valeurs 16 bit (4/4)",set_tag("T4", 16), SUCCES_TO_SET);
00213 
00214     // Le prochain tag doit etre refuse faute d'espace libre.
00215     printf("\ttest de Dépassement de l'espace mémoire (8 octets max)\n");
00216     TEST_EQ_INT("avec 1 bit",set_tag("T5", 1), CAN_TG_ERROR_NOT_ENOUNG_SPACE);
00217     TEST_EQ_INT("avec 16 bits",set_tag("T6", 16), CAN_TG_ERROR_NOT_ENOUNG_SPACE);
00218     printf("OK\n");
00219 
00220     // ---------------------------------------------------------
00221     // TEST 3 : Cas d'erreurs de set_value et get_value
00222     // ---------------------------------------------------------
00223     printf("Test 3: Erreurs et depassements de valeurs... ");
00224     init_tag_manager();
00225     init_data_container();
00226     printf("\tpreparation du GT\n");
00227     TEST_EQ_INT("prepa... ",set_tag("BIT_1", 1), SUCCES);
00228     TEST_EQ_INT("prepa... ",set_tag("BIT_3", 3), SUCCES);
00229     TEST_EQ_INT("prepa... ",set_tag("BIT_4", 4), SUCCES);
00230 
00231     // Tag inexistant (retour attendu: -3)
00232     printf("\tTag inexistant\n");
00233     TEST_EQ_INT("test set",set_value("FANTOME", 5), -3);
00234     TEST_EQ_INT("test get",get_value("FANTOME", &val), -3);
00235 
00236     // Depassement de capacite:
00237     // NOTE: l'implementation actuelle renvoie CAN_TG_ERROR_VALUE_TO_BIG (-10),
00238     // mais ces assertions historiques verifient encore -4.
00239     printf("\tDépassement de capacité\n");
00240     // - Un tag de 1 bit ne peut contenir que 0 ou 1
00241     TEST_EQ_INT("Un tag de 1 bits[0 ou 1]",set_value("BIT_1", 2), -4);
00242     // - Un tag de 3 bits ne peut contenir que de 0 à 7
00243     TEST_EQ_INT("Un tag de 3 bits [0 à 7]",set_value("BIT_3", 8), -4);
00244     // - Un tag de 4 bits ne peut contenir que de 0 à 15
00245     TEST_EQ_INT("Un tag de 4 bits [0 à 15]", set_value("BIT_4", 16), -4);
00246     printf("OK\n");
00247 
00248     // ---------------------------------------------------------
00249     // TEST 4 : Indépendance des écritures (Masquage binaire)
00250     // ---------------------------------------------------------
00251     printf("Test 4: Indépendance des bits contigus... ");
00252     init_tag_manager();
00253     init_data_container();
00254 
00255     // On crée une configuration qui remplit exactement 1 octet (1 + 3 + 4 = 8 bits)
00256     printf("\tpreparation du GT\n");
00257     TEST_EQ_INT("preparation [set_tag] (1/3)",set_tag("T_1", 1), SUCCES);
00258     TEST_EQ_INT("preparation [set_tag] (2/3)",set_tag("T_3", 3), SUCCES);
