00264     TEST_EQ_INT("preparation [set_tag] (7) 3 bits (2/3)",set_value("T_3", 7), SUCCES);
00265     TEST_EQ_INT("preparation [set_tag] (15) 4 bits (3/3)",set_value("T_4", 15), SUCCES);
00266 
00267     // On vérifie qu'elles sont bien mémorisées
00268     printf("\t\n");
00269     get_value("T_1", &val);
