00271     get_value("T_3", &val);
00272     TEST_EQ_INT("get value T_3",val, 7);
00273     get_value("T_4", &val);
00274     TEST_EQ_INT("get value T_4",val, 15);
00275 
00276     // On modifie T_3 sans toucher aux autres
