00283     TEST_EQ_INT("verif valeur [encien]",val, 1);
00284     get_value("T_3", &val);
00285     TEST_EQ_INT("verif valeur [nouvel]",val, 2); // Nouvelle valeur
00286     get_value("T_4", &val);
00287     TEST_EQ_INT("verif valeur [encien]",val, 15);
00288     printf("OK\n");
00289 
00290     // ---------------------------------------------------------
00291     // TEST 5 : Variables de 8 bits
00292     // ---------------------------------------------------------
00293     printf("Test 5: Variables 8 bits... ");
00294     init_tag_manager();
00295     init_data_container();
00296     printf("\t\n");
00297     TEST_EQ_INT("prapa de la valeur",set_tag("V8", 8), SUCCES);
00298 
00299     // Test des bornes 0 et 255
00300     printf("\tTest des bornes 0 et 255\n");
00301     set_value("V8", 0);
00302     get_value("V8", &val);
00303     TEST_EQ_INT("val = 0",val, 0);
00304     set_value("V8", 255);
00305     get_value("V8", &val);
00306     TEST_EQ_INT("val = 255",val, 255);
00307     printf("\tErreur dépassement\n");
00308     TEST_EQ_INT("val: [256]",set_value("V8", 256), -4); // Assertion historique, a realigner avec -10
00309     printf("OK\n");
00310 
00311     //--------------------------------------
00312     // TEST 6: Tout les test de 4 bits
00313     //--------------------------------------
00314     printf("\ttest de tags à 4 bits (tout les type possible)\n");
00315     init_tag_manager();
00316     init_data_container();
00317     printf("test d'inserssion des tags\n");
00318     TEST_EQ_INT("ajout 1 tags à 4 bits ", set_tag("ma_val1", 4),SUCCES);
00319     TEST_EQ_INT("ajout 1 tags après 4 bits ", set_tag("ma_2", 4),SUCCES);
00320     printf("le dernier cas n'ais pas encore testé!!!!\n");
00321     printf("test  d'ajout de valeurs\n");
00322     TEST_EQ_INT("set val",set_value("ma_val1", 3),1);
00323     TEST_EQ_INT("set val 2",set_value("ma_2", 9),1);
00324     get_value("ma_val1", &val);
00325     TEST_EQ_INT("get val 1",val,3);;
00326     get_value("ma_2", &val);
00327     TEST_EQ_INT("get val 2",val,9);;
00328     //printf("=== TOUS LES TESTS SONT PASSES AVEC SUCCES ! ===\n\n");
00329 }
